DRC Explanation Script
There are times when the designer has a DRC rule name or a pattern of DRC rules and wants to get an explanation about what these rules are doing. This can be done by reporting properties on the DRC objects. The example script below takes as input a pattern matching a set of DRC rule(s) and prints some explanation (s...
proc explain_drc { drcs } {
    package require struct::matrix
    set loop_drcs [get_drc_checks $drcs -quiet]
    if {$loop_drcs == {}} {
    puts "Error: $drcs does not match any existing DRC rule"
    return
    }
    struct::matrix drcsm
    drcsm add columns 3
    drcsm add row {DRC_ID SEVERITY DESCRIPTION}
    foreach drc $loop_drcs {
    set description "\\{[get_property DESCRIPTION [get_drc_checks $drc]]\""
    set severity "\\{[get_property SEVERITY [get_drc_checks $drc]]\""
    set key "\\{[get_property NAME [get_drc_checks $drc]]\""
    drcsm add row "$key $severity $description"
    }
    puts "[drcsm format 2chan]";
    drcsm destroy
}

